// BatchDashboard.js
import React from 'react';
// Assuming the necessary CSS is already loaded via App.js or BatchAnalysis.js
// If you want dedicated dashboard styling, you'd import it here.

function BatchDashboard({ dashboardData }) {
    if (!dashboardData || !dashboardData.batchResult) {
        return (
            <div style={{ padding: '20px', textAlign: 'center', color: '#94a3b8' }}>
                <h2>📊 Batch Analysis Dashboard</h2>
                <p>No batch analysis results available. Please navigate to 'Batch Processing' and run an analysis first.</p>
            </div>
        );
    }
    
    // In a final application, you would render the complex scorecard,
    // segmentation cards, and charts here, using the data passed in via dashboardData.batchResult.
    // For now, we'll display a summary.
    
    const results = dashboardData.batchResult.full_response;
    const totalCustomers = results.summary.total_customers_processed;
    const highRiskCount = results.summary.risk_distribution['P1: High Risk (>70%)'] || 0;
    const potentialLoss = (results.business_impact.total_potential_loss / 100000).toFixed(1);

    return (
        <div className="batch-dashboard-view" style={{ padding: '20px', maxWidth: '1200px', margin: 'auto' }}>
            <h2 style={{ color: '#f8fafc', borderBottom: '2px solid #334155', paddingBottom: '10px' }}>
                ⚡ Executive Batch Analysis Report
            </h2>
            <p style={{ color: '#94a3b8' }}>Generated: {dashboardData.timestamp}</p>
            
            <div className="kpi-grid" style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '20px', marginTop: '30px' }}>
                <div className="kpi-card" style={{ background: '#1e293b', padding: '20px', borderRadius: '12px', border: '1px solid #475569' }}>
                    <div className="kpi-title" style={{ color: '#94a3b8', fontSize: '14px' }}>Total Customers Processed</div>
                    <div className="kpi-value" style={{ color: '#06b6d4', fontSize: '28px', fontWeight: 'bold' }}>{totalCustomers.toLocaleString()}</div>
                </div>
                <div className="kpi-card" style={{ background: '#1e293b', padding: '20px', borderRadius: '12px', border: '1px solid #475569' }}>
                    <div className="kpi-title" style={{ color: '#94a3b8', fontSize: '14px' }}>High-Risk Customers</div>
                    <div className="kpi-value" style={{ color: '#ef4444', fontSize: '28px', fontWeight: 'bold' }}>{highRiskCount}</div>
                </div>
                <div className="kpi-card" style={{ background: '#1e293b', padding: '20px', borderRadius: '12px', border: '1px solid #475569' }}>
                    <div className="kpi-title" style={{ color: '#94a3b8', fontSize: '14px' }}>Potential Revenue Loss</div>
                    <div className="kpi-value" style={{ color: '#34d399', fontSize: '28px', fontWeight: 'bold' }}>₹{potentialLoss} Lakh</div>
                </div>
            </div>

            <h3 style={{ marginTop: '40px', color: '#f8fafc' }}>Top Insight</h3>
            <div style={{ background: '#1e293b', padding: '20px', borderRadius: '12px', border: '4px solid #7c3aed' }}>
                <p style={{ color: '#cbd5e1' }}>
                    The current analysis identifies **{highRiskCount} customers** in the highest risk segment, 
                    representing a total potential revenue loss of **₹{potentialLoss} Lakh**. 
                    Immediate high-touch retention campaigns are recommended for this group.
                </p>
            </div>
        </div>
    );
}

export default BatchDashboard;
